1	import { createContext, useContext, useState, useCallback, type ReactNode } from "react";
2	import type { Session } from "@/lib/api/types";
3	
4	const STORAGE_KEY = "bayes-session";
5	
6	function loadSession(): Session {
7	  try {
8	    const raw = localStorage.getItem(STORAGE_KEY);
9	    if (raw) {
10	      const parsed = JSON.parse(raw) as Session;
11	      return { accountId: parsed.accountId ?? "", agentId: parsed.agentId ?? "" };
12	    }
13	  } catch {
14	    // ignore corrupt storage
15	  }
16	  return { accountId: "", agentId: "" };
17	}
18	
19	function saveSession(session: Session): void {
20	  localStorage.setItem(STORAGE_KEY, JSON.stringify(session));
21	}
22	
23	interface SessionContextValue {
24	  session: Session;
25	  setAccountId: (id: string) => void;
26	  setAgentId: (id: string) => void;
27	  isConfigured: boolean;
28	}
29	
30	const SessionContext = createContext<SessionContextValue | null>(null);
31	
32	export function SessionProvider({ children }: { children: ReactNode }) {
33	  const [session, setSession] = useState<Session>(loadSession);
34	
35	  const setAccountId = useCallback((accountId: string) => {
36	    setSession((prev) => {
37	      const next = { ...prev, accountId };
38	      saveSession(next);
39	      return next;
40	    });
41	  }, []);
42	
43	  const setAgentId = useCallback((agentId: string) => {
44	    setSession((prev) => {
45	      const next = { ...prev, agentId };
46	      saveSession(next);
47	      return next;
48	    });
49	  }, []);
50	
51	  return (
52	    <SessionContext.Provider
53	      value={{ session, setAccountId, setAgentId, isConfigured: session.accountId.length > 0 }}
54	    >
55	      {children}
56	    </SessionContext.Provider>
57	  );
58	}
59	
60	export function useSession(): SessionContextValue {
61	  const ctx = useContext(SessionContext);
62	  if (!ctx) throw new Error("useSession must be used within SessionProvider");
63	  return ctx;
64	}
65

