44	async function request<T>(
45	  path: string,
46	  options: RequestInit = {},
47	  session?: Session,
48	): Promise<T> {
49	  const headers: Record<string, string> = {
50	    ...(options.headers as Record<string, string>),
51	  };
52	
53	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
54	    headers["Content-Type"] = "application/json";
55	  }
56	
57	  if (session?.agentId) {
58	    headers["X-Bayes-Agent-Id"] = session.agentId;
59	  }
60	
61	  const res = await fetch(`${API_BASE}${path}`, {
62	    ...options,
63	    headers,
64	  });
65	
66	  const body = await res.json();
67	
68	  if (!res.ok) {
69	    const err = body as ApiError;
70	    throw new BayesApiError(
71	      res.status,
72	      err.error?.code ?? "unknown_error",
73	      err.error?.details ?? {},
74	    );
75	  }
76	
77	  return body as T;
78	}
