39	  }
40	
41	  const exposure = exposureQuery.data?.account.exposure;
42	  const risk = riskQuery.data?.account.risk;
43	  const hasExposure = exposure != null;
44	  const hasRisk = risk != null;
45	  const exposureMissing = isAccountNotFoundError(exposureQuery.error);
46	  const riskMissing = isAccountNotFoundError(riskQuery.error);
47	  const exposurePending = !hasExposure && exposureQuery.isPending;
48	  const riskPending = !hasRisk && riskQuery.isPending;
49	  const exposureError = exposureQuery.error && !exposureMissing ? exposureQuery.error : null;
50	  const riskError = riskQuery.error && !riskMissing ? riskQuery.error : null;
51	  const hasNoAccountData = !hasExposure && !hasRisk;
52	  const waitingForMissingAccountCompanion = hasNoAccountData
53	    && ((exposureMissing && riskPending) || (riskMissing && exposurePending));
54	  const positions = [...(exposure?.positions ?? [])].sort(
55	    (left, right) => new Date(right.updatedAt).getTime() - new Date(left.updatedAt).getTime(),
