70	function isMarketStatus(value: unknown): value is MarketStatus {
71	  return value === "active" || value === "resolved" || value === "closed" || value === "draft";
72	}
73	
74	function isRecord(value: unknown): value is Record<string, unknown> {
75	  return typeof value === "object" && value !== null;
76	}
77	
78	function parseMarginals(value: unknown): Record<string, number> | null {
79	  if (!isRecord(value)) {
80	    return null;
81	  }
82	
83	  const marginals: Record<string, number> = {};
84	  for (const [outcomeId, probability] of Object.entries(value)) {
85	    if (typeof probability !== "number" || !Number.isFinite(probability)) {
86	      return null;
87	    }
88	    marginals[outcomeId] = probability;
89	  }
90	  return marginals;
91	}
92	
93	function parseMarketPriceMessage(value: unknown): MarketPriceMessage | null {
94	  if (!isRecord(value)) {
95	    return null;
96	  }
97	
98	  if (
99	    typeof value.marketId !== "string"
100	    || !isMarketStatus(value.status)
101	    || typeof value.seq !== "number"
102	    || !Number.isFinite(value.seq)
103	    || typeof value.emittedAt !== "string"
104	    || typeof value.approxFlag !== "boolean"
105	  ) {
106	    return null;
107	  }
108	
109	  const marginals = parseMarginals(value.marginals);
110	  if (!marginals) {
111	    return null;
112	  }
113	
114	  let resolutionProbabilities: Record<string, number> | undefined;
115	  if (value.resolutionProbabilities != null) {
116	    const parsedResolutionProbabilities = parseMarginals(value.resolutionProbabilities);
117	    if (!parsedResolutionProbabilities) {
118	      return null;
119	    }
120	    resolutionProbabilities = parsedResolutionProbabilities;
121	  }
122	
123	  return {
124	    marketId: value.marketId,
125	    status: value.status,
126	    marginals,
127	    seq: value.seq,
128	    emittedAt: value.emittedAt,
129	    approxFlag: value.approxFlag,
130	    resolution: typeof value.resolution === "string" ? value.resolution : undefined,
131	    resolutionProbabilities,
132	  };
133	}
