135	export function useMarketPriceSubscription(marketId: string, opts?: { enabled?: boolean }) {
136	  const qc = useQueryClient();
137	  const enabled = opts?.enabled ?? true;
138	  const lastSeqRef = useRef<number>(-1);
139	  const reconnectAttemptRef = useRef(0);
140	  const reconnectTimerRef = useRef<number | null>(null);
141	
142	  useEffect(() => {
143	    if (!enabled || marketId.length === 0) {
144	      lastSeqRef.current = -1;
145	      reconnectAttemptRef.current = 0;
146	      if (reconnectTimerRef.current != null) {
147	        window.clearTimeout(reconnectTimerRef.current);
148	        reconnectTimerRef.current = null;
149	      }
150	      return;
151	    }
152	
153	    lastSeqRef.current = -1;
154	    reconnectAttemptRef.current = 0;
155	
156	    let socket: WebSocket | null = null;
157	    let effectClosed = false;
158	    let terminalStatus: MarketStatus | null = null;
159	
160	    const clearReconnectTimer = () => {
161	      if (reconnectTimerRef.current != null) {
162	        window.clearTimeout(reconnectTimerRef.current);
163	        reconnectTimerRef.current = null;
164	      }
165	    };
166	
167	    const scheduleReconnect = () => {
168	      clearReconnectTimer();
169	      const attempt = reconnectAttemptRef.current;
170	      const delay = Math.min(
171	        MAX_RECONNECT_DELAY_MS,
172	        INITIAL_RECONNECT_DELAY_MS * (2 ** attempt),
173	      );
174	      reconnectAttemptRef.current += 1;
175	      reconnectTimerRef.current = window.setTimeout(() => {
176	        if (effectClosed || terminalStatus !== null) {
177	          return;
178	        }
179	        refetchMarketRouteQueries(qc, marketId);
180	        connect();
181	      }, delay);
182	    };
183	
184	    const connect = () => {
185	      if (effectClosed || terminalStatus !== null) {
186	        return;
187	      }
188	
189	      socket = new WebSocket(api.getMarketPricesWebSocketUrl(marketId));
190	
191	      socket.addEventListener("open", () => {
192	        const reconnecting = reconnectAttemptRef.current > 0;
193	        reconnectAttemptRef.current = 0;
194	        clearReconnectTimer();
195	        if (reconnecting) {
196	          refetchMarketRouteQueries(qc, marketId);
197	        }
198	      });
199	
200	      socket.addEventListener("message", (event) => {
201	        if (typeof event.data !== "string") {
202	          return;
203	        }
204	
205	        let raw: unknown;
206	        try {
207	          raw = JSON.parse(event.data);
208	        } catch {
209	          return;
210	        }
211	
212	        const update = parseMarketPriceMessage(raw);
213	        if (!update || update.marketId !== marketId || update.seq <= lastSeqRef.current) {
214	          return;
215	        }
216	
217	        lastSeqRef.current = update.seq;
218	        qc.setQueryData<MarketDetailResponse>(queryKeys.market(marketId), (current) => {
219	          if (!current) {
220	            return current;
221	          }
222	
223	          return {
224	            ...current,
225	            market: {
226	              ...current.market,
227	              status: update.status,
228	              marginals: update.marginals,
229	              resolution: update.resolution ?? current.market.resolution,
230	              resolutionProbabilities: update.resolutionProbabilities ?? current.market.resolutionProbabilities,
231	            },
232	          };
233	        });
234	
235	        invalidateMarketDependentQueries(qc, marketId);
236	
237	        if (update.status !== "active") {
238	          terminalStatus = update.status;
239	          refetchMarketRouteQueries(qc, marketId);
240	          socket?.close();
241	        }
242	      });
243	
244	      socket.addEventListener("error", () => {
245	        socket?.close();
246	      });
247	
248	      socket.addEventListener("close", () => {
249	        socket = null;
250	        if (effectClosed) {
251	          return;
252	        }
253	
254	        if (terminalStatus !== null) {
255	          return;
256	        }
257	
258	        refetchMarketRouteQueries(qc, marketId);
259	        scheduleReconnect();
260	      });
261	    };
262	
263	    connect();
264	
265	    return () => {
266	      effectClosed = true;
267	      clearReconnectTimer();
268	      reconnectAttemptRef.current = 0;
269	      terminalStatus = null;
270	      socket?.close();
271	      socket = null;
272	    };
273	  }, [enabled, marketId, qc]);
274	}
